// Solution
function validateCherryPickedCommitHash(commitHash) {
  const regex = /^[0-9a-fA-F]{40}$/;
  return regex.test(commitHash);
}

solutions.python:
class Solution:
    def validateCherryPickedCommitHash(self, commitHash: str) -> bool:
        import re
        return bool(re.match('^[0-9a-fA-F]{40}$', commitHash))
